        private List<string> ValidateAndParseColumns(string selectColumns)
        {
            if (string.IsNullOrWhiteSpace(selectColumns))
            {
                return AllowedColumns.Take(5).ToList();
            }

            var columns = selectColumns.Split(',', StringSplitOptions.RemoveEmptyEntries)
                .Select(c => c.Trim())
                .Where(c => AllowedColumns.Contains(c))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            return columns.Count > 0 && columns.Count <= 20 ? columns : null;
        }

        private List<FilterCondition> ParseAndValidateFilters(System.Collections.Specialized.NameValueCollection queryParams)
        {
            var filters = new List<FilterCondition>();

            foreach (string key in queryParams.AllKeys)
            {
                if (key == null || key.Equals("table", StringComparison.OrdinalIgnoreCase) ||
                    key.Equals("select", StringComparison.OrdinalIgnoreCase) ||
                    key.Equals("orderBy", StringComparison.OrdinalIgnoreCase) ||
                    key.Equals("sortDirection", StringComparison.OrdinalIgnoreCase) ||
                    key.Equals("pageSize", StringComparison.OrdinalIgnoreCase) ||
                    key.Equals("pageNumber", StringComparison.OrdinalIgnoreCase))
                {
                    continue;
                }

                var parts = key.Split('_');
                if (parts.Length != 2)
                {
                    continue;
                }

                string column = parts[0];
                string operatorKey = parts[1];

                if (!AllowedColumns.Contains(column) || !AllowedOperators.Contains(operatorKey))
                {
                    return null;
                }

                string value = queryParams[key];
                if (string.IsNullOrWhiteSpace(value) || value.Length > 500)
                {
                    return null;
                }

                if (!ValidateValueFormat(value, operatorKey))
                {
                    return null;
                }

                filters.Add(new FilterCondition
                {
                    Column = column,
                    Operator = operatorKey,
                    Value = value
                });
            }

            return filters.Count <= 10 ? filters : null;
        }

        private bool ValidateValueFormat(string value, string operatorKey)
        {
            if (operatorKey.Equals("in", StringComparison.OrdinalIgnoreCase))
            {
                var values = value.Split(',', StringSplitOptions.RemoveEmptyEntries);
                return values.Length > 0 && values.Length <= 50 && values.All(v => IsValidSingleValue(v.Trim()));
            }

            return IsValidSingleValue(value);
        }

        private bool IsValidSingleValue(string value)
        {
            if (string.IsNullOrWhiteSpace(value) || value.Length > 200)
            {
                return false;
            }

            if (Regex.IsMatch(value, @"[;'""\\]|--|\*|xp_|sp_|exec|execute|drop|delete|insert|update|create|alter|truncate", RegexOptions.IgnoreCase))
            {
                return false;
            }

            return true;
        }

        private string ValidateOrderBy(string orderBy, string sortDirection)
        {
            if (string.IsNullOrWhiteSpace(orderBy))
            {
                return null;
            }

            if (!AllowedColumns.Contains(orderBy))
            {
                return null;
            }

            string direction = "ASC";
            if (!string.IsNullOrWhiteSpace(sortDirection))
            {
                if (sortDirection.Equals("desc", StringComparison.OrdinalIgnoreCase))
                {
                    direction = "DESC";
                }
                else if (!sortDirection.Equals("asc", StringComparison.OrdinalIgnoreCase))
                {
                    return null;
                }
            }

            return $"[{orderBy}] {direction}";
        }

        private int ParsePositiveInt(string value, int defaultValue, int min, int max)
        {
            if (int.TryParse(value, out int result))
            {
                return Math.Max(min, Math.Min(max, result));
            }
            return defaultValue;
        }

        private async Task<object> ExecuteSecureQuery(
            string table,
            List<string> columns,
            List<FilterCondition> filters,
            string orderByClause,
            int pageSize,
            int pageNumber,
            string connectionString)
        {
            var selectClause = string.Join(", ", columns.Select(c => $"[{c}]"));
            var offset = (pageNumber - 1) * pageSize;

            using (var connection = new SqlConnection(connectionString))
            {
                await connection.OpenAsync();

                using (var command = connection.CreateCommand())
                {
                    var queryBuilder = new StringBuilder();
                    queryBuilder.Append($"SELECT {selectClause} FROM [{table}]");

                    if (filters.Count > 0)
                    {
                        queryBuilder.Append(" WHERE ");
                        var whereClauses = new List<string>();

                        for (int i = 0; i < filters.Count; i++)
                        {
                            var filter = filters[i];
                            var paramName = $"@param{i}";
                            var sqlOperator = OperatorMap[filter.Operator];

                            if (filter.Operator.Equals("in", StringComparison.OrdinalIgnoreCase))
                            {
                                var values = filter.Value.Split(',', StringSplitOptions.RemoveEmptyEntries);
                                var inParams = new List<string>();
                                
                                for (int j = 0; j < values.Length; j++)
                                {
                                    var inParamName = $"@param{i}_{j}";
                                    inParams.Add(inParamName);
                                    command.Parameters.Add(new SqlParameter(inParamName, SqlDbType.NVarChar, 200) { Value = values[j].Trim() });
                                }
                                
                                whereClauses.Add($"[{filter.Column}] IN ({string.Join(", ", inParams)})");
                            }
                            else if (filter.Operator.Equals("like", StringComparison.OrdinalIgnoreCase))
                            {
                                whereClauses.Add($"[{filter.Column}] LIKE {paramName}");
                                command.Parameters.Add(new SqlParameter(paramName, SqlDbType.NVarChar, 200) { Value = $"%{filter.Value}%" });
                            }
                            else
                            {
                                whereClauses.Add($"[{filter.Column}] {sqlOperator} {paramName}");
                                command.Parameters.Add(new SqlParameter(paramName, SqlDbType.NVarChar, 200) { Value = filter.Value });
                            }
                        }

                        queryBuilder.Append(string.Join(" AND ", whereClauses));
                    }

                    if (!string.IsNullOrWhiteSpace(orderByClause))
                    {
                        queryBuilder.Append($" ORDER BY {orderByClause}");
                    }
                    else
                    {
                        queryBuilder.Append($" ORDER BY [{columns[0]}]");
                    }

                    queryBuilder.Append($" OFFSET @offset ROWS FETCH NEXT @pageSize ROWS ONLY");

                    command.Parameters.Add(new SqlParameter("@offset", SqlDbType.Int) { Value = offset });
                    command.Parameters.Add(new SqlParameter("@pageSize", SqlDbType.Int) { Value = pageSize });

                    command.CommandText = queryBuilder.ToString();
                    command.CommandType = CommandType.Text;
                    command.CommandTimeout = 30;

                    var results = new List<Dictionary<string, object>>();

                    using (var reader = await command.ExecuteReaderAsync())
                    {
                        while (await reader.ReadAsync())
                        {
                            var row = new Dictionary<string, object>();
                            for (int i = 0; i < reader.FieldCount; i++)
                            {
                                row[reader.GetName(i)] = reader.IsDBNull(i) ? null : reader.GetValue(i);
                            }
                            results.Add(row);
                        }
                    }

                    return new
                    {
                        data = results,
                        pageNumber = pageNumber,
                        pageSize = pageSize,
                        recordCount = results.Count
                    };
                }
            }
        }

